local _M = {}

-- Secret key for token validation (in production, load from secure config)
local AUTH_SECRET = "your_secret_key_here"
local cjson = require("cjson.safe")

-- Define role hierarchy and permissions
local role_permissions = {
    admin = {
        "/admin/dashboard",
        "/admin/users",
        "/admin/settings",
        "/api/v1/users",
        "/api/v1/reports",
        "/api/v1/config",
        "/api/v1/data",
    },
    editor = {
        "/api/v1/data",
        "/api/v1/reports",
        "/api/v1/content",
    },
    viewer = {
        "/api/v1/data",
        "/api/v1/reports",
    },
}

-- Endpoints that skip permission checks (public endpoints)
local public_endpoints = {
    "/health",
    "/status",
    "/login",
    "/register",
    "/public",
}

-- Check if a URI matches any pattern in a list
local function uri_matches(uri, patterns)
    for _, pattern in ipairs(patterns) do
        if string.find(uri, pattern, 1, true) then
            return true
        end
    end
    return false
end

-- Decode a base64url-encoded string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    local decoded = ngx.decode_base64(input)
    return decoded
end

-- Validate and decode the authentication token (simplified JWT-like validation)
local function validate_token(token)
    if not token or token == "" then
        return nil, "No token provided"
    end

    -- Split token into parts (header.payload.signature)
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end

    if #parts ~= 3 then
        return nil, "Invalid token format"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_b64 .. "." .. payload_b64
    local hmac = ngx.hmac_sha1(AUTH_SECRET, signing_input)
    local expected_signature = ngx.encode_base64(hmac):gsub("+", "-"):gsub("/", "_"):gsub("=", "")

    if signature ~= expected_signature then
        return nil, "Invalid token signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_b64)
    if not payload_json then
        return nil, "Failed to decode token payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "Failed to parse token payload: " .. (err or "unknown error")
    end

    -- Check token expiration
    local now = ngx.time()
    if payload.exp and payload.exp < now then
        return nil, "Token has expired"
    end

    -- Check issued-at time (reject tokens from the future)
    if payload.iat and payload.iat > now + 60 then
        return nil, "Token issued in the future"
    end

    return payload, nil
end

-- Extract token from the Authorization header
local function extract_token()
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        return nil
    end

    -- Support "Bearer <token>" format
    local token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
    if token then
        return token
    end

    -- Also accept raw token
    return auth_header
end

-- Check if user role has permission for the requested URI
local function check_role_permission(role, uri)
    if not role or role == "" then
        return false
    end

    -- Normalize role to lowercase for matching
    local normalized_role = string.lower(role)

    -- Admin role has access to everything
    if normalized_role == "admin" then
        return true
    end

    local permissions = role_permissions[normalized_role]
    if not permissions then
        ngx.log(ngx.WARN, "Unknown role: ", role)
        return false
    end

    -- Check if the URI starts with or matches any allowed path for this role
    for _, allowed_path in ipairs(permissions) do
        -- Exact match
        if uri == allowed_path then
            return true
        end
        -- Prefix match: URI starts with the allowed path
        if string.find(uri, allowed_path, 1, true) == 1 then
            return true
        end
    end

    return false
end

-- Send JSON error response
local function deny_access(status, message)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json"
    local response = cjson.encode({
        error = true,
        status = status,
        message = message,
        timestamp = ngx.time(),
    })
    ngx.say(response)
    return ngx.exit(status)
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri

    ngx.log(ngx.DEBUG, "Access control check for URI: ", uri)

    -- Step 1: Check if the endpoint is public (skip permission checks)
    if uri_matches(uri, public_endpoints) then
        ngx.log(ngx.DEBUG, "Public endpoint accessed, skipping auth: ", uri)
        return
    end

    -- Step 2: Determine if this is a protected admin or API endpoint
    local is_admin_endpoint = string.find(uri, "/admin", 1, true) ~= nil
    local is_api_endpoint = string.find(uri, "/api", 1, true) ~= nil

    -- If the URI does not contain "/admin" or "/api", skip permission checks
    if not is_admin_endpoint and not is_api_endpoint then
        ngx.log(ngx.DEBUG, "Non-protected endpoint, skipping permission check: ", uri)
        return
    end

    -- Step 3: Extract and validate authentication token
    local token = extract_token()
    if not token then
        ngx.log(ngx.WARN, "No authentication token found for protected URI: ", uri)
        return deny_access(ngx.HTTP_UNAUTHORIZED, "Authentication required. Please provide a valid Bearer token.")
    end

    local payload, err = validate_token(token)
    if not payload then
        ngx.log(ngx.WARN, "Token validation failed for URI: ", uri, " - Error: ", err)
        return deny_access(ngx.HTTP_UNAUTHORIZED, "Invalid authentication token: " .. (err or "unknown error"))
    end

    -- Step 4: Extract user information from token payload
    local user_id = payload.sub or payload.user_id
    local user_role = payload.role or payload.roles or "viewer"

    if not user_id then
        ngx.log(ngx.WARN, "Token missing user identifier for URI: ", uri)
        return deny_access(ngx.HTTP_UNAUTHORIZED, "Token missing user identifier")
    end

    -- Store user info in request context for downstream use
    ngx.var.http_x_user_id = nil  -- clear any spoofed headers
    ngx.req.set_header("X-User-Id", tostring(user_id))
    ngx.req.set_header("X-User-Role", tostring(user_role))

    -- Step 5: Check if the user's role has permission for this endpoint
    -- Handle role as string or table
    local has_permission = false

    if type(user_role) == "table" then
        -- User has multiple roles, check each
        for _, role in ipairs(user_role) do
            if check_role_permission(role, uri) then
                has_permission = true
                break
            end
        end
    elseif type(user_role) == "string" then
        -- Handle comma-separated roles
        for role in string.gmatch(user_role, "[^,]+") do
            role = string.match(role, "^%s*(.-)%s*$")  -- trim whitespace
            if check_role_permission(role, uri) then
                has_permission = true
                break
            end
        end
    end

    if not has_permission then
        ngx.log(ngx.WARN, "Access denied for user: ", user_id, " with role: ", 
                tostring(user_role), " to URI: ", uri)
        return deny_access(ngx.HTTP_FORBIDDEN, 
            "Access denied. Your role does not have permission to access this resource.")
    end

    -- Step 6: Additional checks for admin endpoints
    if is_admin_endpoint then
        local normalized_role = type(user_role) == "string" and string.lower(user_role) or ""
        local is_admin = false

        if type(user_role) == "table" then
            for _, role in ipairs(user_role) do
                if string.lower(role) == "admin" then
                    is_admin = true
                    break
                end
            end
        elseif string.find(normalized_role, "admin", 1, true) then
            is_admin = true
        end

        if not is_admin then
            ngx.log(ngx.WARN, "Non-admin user attempted admin access: ", user_id, 
                    " role: ", tostring(user_role), " URI: ", uri)
            return deny_access(ngx.HTTP_FORBIDDEN, 
                "Admin access required. This endpoint is restricted to administrators.")
        end
    end

    -- Step 7: Rate limiting context (optional, set headers for downstream)
    ngx.req.set_header("X-Rate-Limit-Group", tostring(user_role))

    ngx.log(ngx.INFO, "Access granted for user: ", user_id, " role: ", 
            tostring(user_role), " URI: ", uri)
end

-- Utility: Generate a simple token for testing purposes
function _M.generate_test_token(user_id, role, expiry_seconds)
    local header = ngx.encode_base64('{"alg":"HS1","typ":"JWT"}'):gsub("+", "-"):gsub("/", "_"):gsub("=", "")
    
    local payload_data = {
        sub = user_id,
        role = role,
        iat = ngx.time(),
        exp = ngx.time() + (expiry_seconds or 3600),
    }
    
    local payload = ngx.encode_base64(cjson.encode(payload_data)):gsub("+", "-"):gsub("/", "_"):gsub("=", "")
    local signing_input = header .. "." .. payload
    local signature = ngx.encode_base64(ngx.hmac_sha1(AUTH_SECRET, signing_input)):gsub("+", "-"):gsub("/", "_"):gsub("=", "")
    
    return header .. "." .. payload .. "." .. signature
end

